from datetime import datetime

from session_gate import in_regular_session


def test_replay_frame_inside_session_is_accepted():
    assert in_regular_session(datetime(2026, 7, 10, 10, 15)) is True


def test_replay_frame_after_session_is_rejected():
    assert in_regular_session(datetime(2026, 7, 10, 20, 0)) is False
